import kotlin.math.sqrt

fun isPrime(n: Int): Boolean {
    if (n <= 1) return false
    if (n == 2) return true
    if (n % 2 == 0) return false
    val maxDivisor = sqrt(n.toDouble()).toInt() + 1
    for (i in 3..maxDivisor step 2) {
        if (n % i == 0) return false
    }
    return true
}

fun solve(nums: Array<Long>): Long {
    var sumA = 0L
    var sumB = 0L
    for ((index, num) in nums.withIndex()) {
        if (isPrime(index)) {
            sumA += num
        } else {
            sumB += num
        }
    }
    return kotlin.math.abs(sumA - sumB)
}
